package com.chaobo.scm.supplier.interfaces.web;
import com.chaobo.scm.common.api.ApiResponse;import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.application.returning.*;import jakarta.servlet.http.*;import jakarta.validation.*;import jakarta.validation.constraints.*;import org.springframework.web.bind.annotation.*;import java.math.BigDecimal;import java.util.Map;
@RestController @RequestMapping("/internal/supplier/v1/returns/events")public class SupplierReturnEventController{private final SupplierReturnEventConsumerApplicationService service;public SupplierReturnEventController(SupplierReturnEventConsumerApplicationService service){this.service=service;}@PostMapping public ApiResponse<Void> consume(@Valid @RequestBody Request b,HttpServletRequest r){String source=r.getHeader("X-Source-System"),eventCode=r.getHeader("X-Event-Code");if(source==null||eventCode==null)throw new BusinessException(ErrorCode.VALIDATION_FAILED,"缺少事件请求头");service.consume(new SupplierReturnExternalEvent(source,eventCode,b.eventType(),b.returnId(),b.success(),b.referenceNo(),b.shipmentId(),b.waybillNo(),b.carrierCode(),b.lineQuantities(),b.offsetAmount(),b.claimAmount(),b.reason()));return ApiResponse.success(null,r.getHeader("X-Request-Id"),r.getHeader("X-Trace-Id"));}public record Request(@NotBlank String eventType,@Positive long returnId,boolean success,String referenceNo,String shipmentId,String waybillNo,String carrierCode,Map<Long,BigDecimal> lineQuantities,BigDecimal offsetAmount,BigDecimal claimAmount,String reason){}
}
